// Initialize backup run metadata
const now = new Date();
return [{
  json: {
    backupStartedAt: now.toISOString(),
    backupDate: now.toISOString().split('T')[0],
    commitMessage: `chore: n8n backup ${now.toISOString().split('T')[0]} at ${now.toTimeString().split(' ')[0]} UTC`
  }
}];

// Build a folder path map from folder list
// Input 0: workflows list, Input 1: folder list
const workflowsData = $input.first().json;
const foldersData = $input.last().json;

// Handle both paginated and direct responses
const workflows = workflowsData.data || workflowsData || [];
const folders = foldersData.data || foldersData || [];

// Build folder id -> full path map (handles nested folders)
const folderMap = {};
folders.forEach(f => {
  folderMap[f.id] = { name: f.name, parentId: f.parentId || null };
});

function getFolderPath(folderId) {
  if (!folderId || !folderMap[folderId]) return '';
  const parts = [];
  let current = folderId;
  let depth = 0;
  while (current && folderMap[current] && depth < 20) {
    parts.unshift(folderMap[current].name.replace(/[<>:"/\\|?*]/g, '_'));
    current = folderMap[current].parentId;
    depth++;
  }
  return parts.join('/');
}

// Map each workflow to its GitHub file path
const result = workflows.map(wf => {
  const folderPath = getFolderPath(wf.folderId || wf.parentFolderId);
  const safeName = (wf.name || `workflow_${wf.id}`).replace(/[<>:"/\\|?*]/g, '_').replace(/\s+/g, '_');
  const filePath = folderPath
    ? `workflows/${folderPath}/${safeName}_${wf.id}.json`
    : `workflows/${safeName}_${wf.id}.json`;

  return {
    json: {
      workflowId: wf.id,
      workflowName: wf.name,
      isActive: wf.active,
      folderId: wf.folderId || wf.parentFolderId || null,
      folderPath: folderPath,
      githubFilePath: filePath,
      tags: wf.tags || [],
      createdAt: wf.createdAt,
      updatedAt: wf.updatedAt
    }
  };
});

return result;

// Prepare the GitHub upsert payload
// Merge path metadata with full workflow JSON
const pathMeta = $('build-file-paths').item.json;
const fullWorkflow = $input.item.json;

// Pretty-print workflow JSON for readability
const content = JSON.stringify(fullWorkflow, null, 2);

// Base64 encode for GitHub API
const base64Content = Buffer.from(content).toString('base64');

return [{
  json: {
    ...pathMeta,
    fileContent: content,
    base64Content: base64Content,
    fileSizeBytes: Buffer.byteLength(content, 'utf8')
  }
}];

// Extract SHA from existing file (needed for updates)
// If 404, file doesn't exist yet (new file)
const checkResponse = $input.item.json;
const previousPayload = $('prepare-github-payload').item.json;

let existingSha = null;
let isNewFile = true;

try {
  // HTTP 200 means file exists
  if (checkResponse.statusCode === 200 || (checkResponse.body && checkResponse.body.sha)) {
    const body = typeof checkResponse.body === 'string'
      ? JSON.parse(checkResponse.body)
      : checkResponse.body;
    existingSha = body.sha || null;
    isNewFile = false;
  }
} catch (e) {
  // File doesn't exist or error - treat as new
  isNewFile = true;
}

return [{
  json: {
    ...previousPayload,
    existingSha,
    isNewFile,
    action: isNewFile ? 'CREATE' : 'UPDATE'
  }
}];

// Skip if content hasn't changed (compare sizes / hashes)
// We'll let GitHub handle this - always push, GitHub deduplicates
const item = $input.item.json;

// Build the GitHub PUT body
const commitMsg = `backup: ${item.workflowName} [${item.workflowId}] - ${new Date().toISOString().split('T')[0]}`;

const body = {
  message: commitMsg,
  content: item.base64Content,
  branch: $env.GITHUB_BRANCH || 'main'
};

// Include SHA for updates (required by GitHub API)
if (item.existingSha) {
  body.sha = item.existingSha;
}

return [{
  json: {
    ...item,
    githubPutBody: JSON.stringify(body),
    commitMessage: commitMsg
  }
}];

// Collect push result
const pushResponse = $input.item.json;
const meta = $('build-commit-body').item.json;

const statusCode = pushResponse.statusCode || 0;
const success = statusCode === 200 || statusCode === 201;

let errorMsg = null;
if (!success) {
  try {
    const body = typeof pushResponse.body === 'string'
      ? JSON.parse(pushResponse.body)
      : pushResponse.body;
    errorMsg = body.message || JSON.stringify(body);
  } catch(e) {
    errorMsg = `HTTP ${statusCode}`;
  }
}

return [{
  json: {
    workflowId: meta.workflowId,
    workflowName: meta.workflowName,
    githubFilePath: meta.githubFilePath,
    folderPath: meta.folderPath,
    isActive: meta.isActive,
    action: meta.action,
    success,
    statusCode,
    errorMsg,
    fileSizeBytes: meta.fileSizeBytes,
    commitMessage: meta.commitMessage
  }
}];

// Aggregate all results and write manifest
const allItems = $input.all();

const successes = allItems.filter(i => i.json.success);
const failures = allItems.filter(i => !i.json.success);

const manifest = {
  backupCompletedAt: new Date().toISOString(),
  totalWorkflows: allItems.length,
  successCount: successes.length,
  failureCount: failures.length,
  created: successes.filter(i => i.json.action === 'CREATE').map(i => i.json.githubFilePath),
  updated: successes.filter(i => i.json.action === 'UPDATE').map(i => i.json.githubFilePath),
  failed: failures.map(i => ({ path: i.json.githubFilePath, error: i.json.errorMsg })),
  workflows: allItems.map(i => ({
    id: i.json.workflowId,
    name: i.json.workflowName,
    active: i.json.isActive,
    folder: i.json.folderPath || '(root)',
    path: i.json.githubFilePath,
    action: i.json.action,
    status: i.json.success ? 'OK' : 'FAILED',
    error: i.json.errorMsg || null,
    sizeBytes: i.json.fileSizeBytes
  }))
};

return [{
  json: {
    manifest,
    base64Manifest: Buffer.from(JSON.stringify(manifest, null, 2)).toString('base64'),
    summary: `✅ ${successes.length} succeeded | ❌ ${failures.length} failed out of ${allItems.length} workflows`
  }
}];

const checkResponse = $input.item.json;
const prev = $('aggregate-results').first().json;

let existingSha = null;
try {
  if (checkResponse.statusCode === 200 || (checkResponse.body && checkResponse.body.sha)) {
    const body = typeof checkResponse.body === 'string'
      ? JSON.parse(checkResponse.body)
      : checkResponse.body;
    existingSha = body.sha || null;
  }
} catch (e) {}

const putBody = {
  message: `chore: update backup manifest ${new Date().toISOString().split('T')[0]}`,
  content: prev.base64Manifest,
  branch: $env.GITHUB_BRANCH || 'main'
};
if (existingSha) putBody.sha = existingSha;

return [{
  json: {
    ...prev,
    manifestPutBody: JSON.stringify(putBody)
  }
}];

const prev = $('aggregate-results').first().json;
const manifest = prev.manifest;

console.log('=== n8n GitHub Backup Complete ===');
console.log(prev.summary);
console.log(`Backup time: ${manifest.backupCompletedAt}`);

if (manifest.failureCount > 0) {
  console.warn('Failed workflows:');
  manifest.failed.forEach(f => console.warn(` - ${f.path}: ${f.error}`));
}

return [{
  json: {
    status: manifest.failureCount === 0 ? 'SUCCESS' : 'PARTIAL_SUCCESS',
    summary: prev.summary,
    backupCompletedAt: manifest.backupCompletedAt,
    totalWorkflows: manifest.totalWorkflows,
    successCount: manifest.successCount,
    failureCount: manifest.failureCount,
    failedWorkflows: manifest.failed
  }
}];
